import { SpotterMenuNavigationDomain } from "src/infra/breadcrumbs";

// TODO:后面放到nacos上面
export const WHITE_LIST = new Set([
    '/', 
    '/403', 
    '/404', 
    '/permission-denied', 
    '/developer-tool',
    '/developer-tool/environment', 
    '/user-center',
    '/mail/detail',
    '/mail/list',
    '/-',
    '/app-center'
]);

// 转为正则 匹配后面带数字的情况 /mail/detail/123
export const WHITE_LIST_REGEX = new RegExp(
`^(${[...WHITE_LIST]
    // eslint-disable-next-line no-useless-escape
    .map(item => `${item}(\/\\d+)?`)
    .join('|')})$`
);

const findMenu = (menus: any[], url: string): any => {
    for (const menusItem of menus) {
        if (menusItem?.routingAddress === url) {
            return menusItem;
        }
        if (menusItem?.children?.length > 0) {
            const childRoute = findMenu(menusItem.children, url);
            if (childRoute) {
                return childRoute;
            }
        }
    }
    return null;
};


const getLongPathMenu = (pathSnippets: string[], menus: SpotterMenuNavigationDomain[])=>{
    const initPath = '';
    if (menus.length){
        const path = pathSnippets.reduce((prev, _, index) => {
            const url = `/${pathSnippets.slice(0, index + 1).join('/')}`;
            const matchMenu = findMenu(menus, url);
            if (matchMenu?.routingAddress?.length > prev?.length) {
                return matchMenu.routingAddress;
            }
            return prev;
        }, initPath);
        return path;
    }
    return initPath
}


const getPathLevel = (pathname:string) => {
    // 删除开头的斜杠，然后根据斜杠分割路径
    const pathSegments = pathname.replace(/^\//, '').split('/');
    const validSegments = pathSegments.filter(segment => segment !== '');
    // 返回路径级别
    return validSegments.length;
}


export const hasPermission = (path: string, remoteMenus: any[]) => {
    if (WHITE_LIST_REGEX.test(path)) {
        // 白名单直接有权限
        return true;
    }

    if (remoteMenus.length === 0) {
        return false;
    }

    /*
        占位菜单路径：- 页面找不到
        一级菜单路径：/x
            菜单路径和当前pathname取最长公共前缀路径，若最长公共前缀路径等于pathname，则有权限
        二级菜单路径：/x/xx
        三级菜单路径：/x/xx/xxx
            若最长公共前缀路径等于菜单路径，则有权限，反之无权限
     */
    const pathSnippets = path?.split('/').filter((p) => p);
    const longPath = getLongPathMenu(pathSnippets, remoteMenus);
    const longPathLevel = getPathLevel(longPath?.startsWith('/') ? longPath : `/${longPath}`);
    const menuPath = findMenu(remoteMenus, longPath);

    // 最长公共连续前缀路径为1级菜单，并且等于当前path
    if(longPathLevel === 1) {
        return longPath === path;
    }

    // 若最长公共前缀路径等于菜单路径
    if(longPathLevel > 1) {
        return menuPath.routingAddress === longPath
    }
    return false;
};
